import './DropdownList.scss';

import { Typography } from ':components/Typography';
import type { FC, ReactNode } from 'react';
import React from 'react';

import { classNames } from '../../../helpers/classnames';
import type { DropdownListProps } from '../Dropdown.types';

const renderStateContent = (content: ReactNode): ReactNode =>
	typeof content === 'string' ? (
		<Typography variant="body2" inactive>
			{content}
		</Typography>
	) : (
		content
	);

export const DropdownList: FC<DropdownListProps> = ({
	loading = false,
	loadingContent,
	empty = false,
	emptyContent,
	headerContent,
	footerContent,
	maxHeight,
	children,
	className,
	style,
	dataTestId = 'DropdownList',
	...props
}) => {
	const scrollStyle = maxHeight ? { ...style, maxHeight: `${maxHeight}px` } : style;

	const renderBody = (): React.ReactNode => {
		if (loading) {
			return (
				<div className="dsb_dropdown-list__state" data-testid={dataTestId + '-loading'}>
					{renderStateContent(loadingContent ?? 'Загрузка…')}
				</div>
			);
		}

		if (empty) {
			return (
				<div className="dsb_dropdown-list__state" data-testid={dataTestId + '-empty'}>
					{renderStateContent(emptyContent ?? 'Нет результатов')}
				</div>
			);
		}

		return children;
	};

	return (
		<div className={classNames('dsb_dropdown-list', className)} data-testid={dataTestId} {...props}>
			{headerContent && <div className="dsb_dropdown-list__header">{headerContent}</div>}
			<div className="dsb_dropdown-list__scroll" role="listbox" style={scrollStyle}>
				{renderBody()}
			</div>
			{footerContent && <div className="dsb_dropdown-list__footer">{footerContent}</div>}
		</div>
	);
};
